class Solution:
    def countPairs(self, coordinates, k):
        n = len(coordinates)
        count = 0
        for i in range(n):
            xi, yi = coordinates[i]
            for j in range(i + 1, n):
                xj, yj = coordinates[j]
                if (xi ^ xj) + (yi ^ yj) == k:
                    count += 1
        return count

