from collections import defaultdict

class Solution:
    def countPairs(self, coordinates, k):
        seen = defaultdict(int)
        ans = 0
        for x, y in coordinates:
            for a in range(k + 1):
                b = k - a
                ans += seen.get((x ^ a, y ^ b), 0)
            seen[(x, y)] += 1
        return ans

