var countPairs = function(coordinates, k) {
    const seen = new Map();
    let ans = 0;
    for (const [x, y] of coordinates) {
        for (let a = 0; a <= k; a++) {
            const b = k - a;
            const key = (x ^ a) + "," + (y ^ b);
            ans += seen.get(key) || 0;
        }
        const ownKey = x + "," + y;
        seen.set(ownKey, (seen.get(ownKey) || 0) + 1);
    }
    return ans;
};
